"use client";

import { useEffect, useState } from "react";
import { SpendSummary, getSpendAnalytics } from "@/lib/analytics";

export default function AnalyticsPage() {
    const [data, setData] = useState<SpendSummary | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        getSpendAnalytics().then(d => {
            setData(d);
            setLoading(false);
        });
    }, []);

    if (loading || !data) return <div>Loading analytics...</div>;

    // Helper for max value to scale charts
    const maxDeptSpend = Math.max(...Object.values(data.spendByDepartment), 1);

    return (
        <div>
            <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', marginBottom: '2rem', color: 'var(--primary)' }}>Spend Analytics</h1>

            {/* KPI Cards */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem', marginBottom: '2rem' }}>
                <div className="card">
                    <h3 style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem' }}>Total Spend (YTD)</h3>
                    <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--primary)' }}>
                        ${data.totalSpend.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </div>
                    <div style={{ fontSize: '0.8rem', color: 'var(--success)' }}>+12% vs last month</div>
                </div>
                <div className="card">
                    <h3 style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem' }}>Active Purchase Orders</h3>
                    <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#0ea5e9' }}>
                        {data.recentTransactions.length}
                    </div>
                </div>
                <div className="card">
                    <h3 style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem' }}>Top Vendor</h3>
                    <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--text-primary)' }}>
                        {Object.entries(data.spendByVendor).sort((a, b) => b[1] - a[1])[0]?.[0] || '-'}
                    </div>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>

                {/* Department Chart */}
                <div className="card">
                    <h3 style={{ fontSize: '1.25rem', fontWeight: 600, marginBottom: '1.5rem' }}>Spend by Department</h3>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        {Object.entries(data.spendByDepartment).map(([dept, amount]) => (
                            <div key={dept}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem', fontSize: '0.9rem' }}>
                                    <span style={{ fontWeight: 500 }}>{dept}</span>
                                    <span>${amount.toLocaleString()}</span>
                                </div>
                                <div style={{ height: '8px', width: '100%', backgroundColor: '#f1f5f9', borderRadius: '4px', overflow: 'hidden' }}>
                                    <div style={{
                                        height: '100%',
                                        width: `${(amount / maxDeptSpend) * 100}%`,
                                        backgroundColor: 'var(--accent)',
                                        borderRadius: '4px',
                                        transition: 'width 1s ease-in-out'
                                    }} />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Vendor Table */}
                <div className="card">
                    <h3 style={{ fontSize: '1.25rem', fontWeight: 600, marginBottom: '1.5rem' }}>Top Vendors</h3>
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                        <tbody>
                            {Object.entries(data.spendByVendor)
                                .sort((a, b) => b[1] - a[1])
                                .slice(0, 5)
                                .map(([vendor, amount], idx) => (
                                    <tr key={vendor} style={{ borderBottom: '1px solid var(--border)' }}>
                                        <td style={{ padding: '0.75rem 0', fontWeight: 500 }}>{idx + 1}. {vendor}</td>
                                        <td style={{ padding: '0.75rem 0', textAlign: 'right', fontWeight: 600 }}>${amount.toLocaleString()}</td>
                                    </tr>
                                ))}
                        </tbody>
                    </table>
                </div>

            </div>
        </div>
    );
}
